namespace sv_a4a09a5eb389475e9a717c519f7ebf1f.Services;

public record WarehouseOption(string Id, string Name);

public class WarehouseInfo
{
    public string SelectedWarehouseId { get; set; } = "WH1";

    public static IReadOnlyList<WarehouseOption> AvailableWarehouses { get; } =
    [
        new("WH1", "Warehouse A – East"),
        new("WH2", "Warehouse B – West"),
        new("WH3", "Warehouse C – Central"),
    ];
}

namespace sv_a4a09a5eb389475e9a717c519f7ebf1f.Services;

/// <summary>
/// Scoped service that tracks low-stock alert counts per warehouse.
/// Components subscribe to <see cref="OnChange"/> to be notified when
/// new data arrives — this is the cross-component notification mechanism.
/// </summary>
public class InventoryAlertService
{
    private readonly Random _random = new();

    public int CurrentAlertCount { get; private set; }
    public string? CurrentWarehouseId { get; private set; }

    /// <summary>
    /// Fired after <see cref="RefreshAsync"/> completes. All subscribed
    /// components (sidebar badge, dashboard, etc.) re-render in response.
    /// </summary>
    public event Action? OnChange;

    /// <summary>Simulates a database query for items below minimum stock levels.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Fetches fresh data and notifies ALL subscribers.
    /// Called by the polling component; every other component that
    /// subscribes to <see cref="OnChange"/> will update automatically.
    /// </summary>
    public async Task RefreshAsync(string warehouseId)
    {
        CurrentWarehouseId = warehouseId;
        CurrentAlertCount = await GetLowStockCountAsync(warehouseId);
        OnChange?.Invoke();
    }
}

