@* Interactive dropdown for choosing the current warehouse.
   Rendered inside the static MainLayout but marked InteractiveServer
   so it can handle change events. Updates the CascadingValueSource
   which pushes the new value to every [CascadingParameter] subscriber. *@

@rendermode InteractiveServer
@inject CascadingValueSource<WarehouseInfo> WarehouseSource
@inject InventoryAlertService AlertService
@using sv_a4a09a5eb389475e9a717c519f7ebf1f.Services

<div class="warehouse-selector">
    <label class="me-2 fw-semibold" for="warehouse-select">📦 Warehouse:</label>
    <select id="warehouse-select"
            class="form-select form-select-sm d-inline-block w-auto"
            value="@_selectedId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseInfo.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    private string _selectedId = "WH1";

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        _selectedId = e.Value?.ToString() ?? "WH1";

        var info = new WarehouseInfo { SelectedWarehouseId = _selectedId };
        await WarehouseSource.NotifyChangedAsync(info);

        // Immediately refresh alerts for the newly selected warehouse
        await AlertService.RefreshAsync(_selectedId);
    }
}

@* Displays the current low-stock alert count as a badge.
   Subscribes to InventoryAlertService.OnChange so it updates
   whenever ANY component triggers a data refresh — not just itself. *@

@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@implements IDisposable
@using sv_a4a09a5eb389475e9a717c519f7ebf1f.Services

@if (AlertService.CurrentAlertCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-1"
          title="@AlertService.CurrentAlertCount items below minimum stock">
        @AlertService.CurrentAlertCount
    </span>
}
else
{
    <span class="badge bg-success rounded-pill ms-1" title="No low-stock alerts">0</span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        // Wrap in InvokeAsync because the event may fire from a timer
        // callback on a non-Blazor thread.
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnChange += _handler;
    }

    public void Dispose()
    {
        AlertService.OnChange -= _handler;
    }
}

